        let p = Project::new("smoke", 2);
        let s = render(&p);
        assert!(
            s.contains(r#"smtFileName0 = "maps/smoke.smt""#),
            "got:\n{s}"
        );
        assert!(s.contains(r#"mapfile = "maps/smoke.smf""#), "got:\n{s}");
