    #[test]
    fn determinism_repeated_render_byte_identical() {
        // NFR-Determinism: render twice, expect byte-identical output.
        let mut p = Project::new("det", 4);
        p.min_height = -10.0;
        p.max_height = 200.0;
        p.start_positions = vec![
            StartPosition {
                team_id: 0,
                x_elmo: 100,
                z_elmo: 100,
            },
            StartPosition {
                team_id: 1,
                x_elmo: 900,
                z_elmo: 900,
            },
        ];
        let a = render(&p);
        let b = render(&p);
        assert_eq!(a, b);
    }

