    #[test]
    fn keys_sorted_alphabetically_top_level() {
        // Determinism + diff-friendliness: scan known top-level keys
        // and assert their positions are in alphabetic order.
        let p = Project::new("sort", 4);
        let s = render(&p);
        let mut last_pos = 0usize;
        for key in [
            "atmosphere",
            "depend",
            "extractorRadius",
            "lighting",
            "mapfile",
            "maphardness",
            "modtype",
            "name",
            "smf",
            "version",
        ] {
            let needle = format!("\n  {} =", key);
            let pos = s.find(&needle).unwrap_or_else(|| {
                panic!("top-level key '{key}' missing in:\n{s}");
            });
            assert!(
                pos > last_pos,
                "key '{key}' out of order at pos {pos} (last {last_pos});\n{s}"
            );
            last_pos = pos;
        }
    }

    #[test]
    fn splats_arrays_render_as_seq() {
        let p = Project::new("splats", 4);
        let s = render(&p);
        // texScales = [0.02; 4]; texMults = [1.0; 4].
        assert!(s.contains("texScales = {"));
        assert!(s.contains("texMults = {"));
        // Each array contains four 0.02 / 1.0 entries.
        let tex_scales_chunk = {
            let start = s.find("texScales = {").unwrap();
            let end_rel = s[start..].find('}').unwrap();
            &s[start..start + end_rel + 1]
        };
        assert_eq!(
            tex_scales_chunk.matches("0.02,").count(),
            4,
            "splats.texScales should have four 0.02 entries; got:\n{tex_scales_chunk}"
        );
    }

